?><!doctype html><html lang="id"><head><meta charset="utf-8"><title>Laporan Akademik PABETAS</title><style>body{font-family:Arial,sans-serif;color:#1e293b} .header{display:flex;align-items:center;gap:16px;border-bottom:4px solid #2563eb;padding-bottom:12px;margin-bottom:18px}.logo{width:70px}.stat{display:inline-block;background:#eff6ff;border-radius:12px;padding:12px;margin:6px}.stat b{display:block;font-size:24px;color:#1d4ed8}table{border-collapse:collapse;width:100%;margin-top:16px}th,td{border:1px solid #cbd5e1;padding:8px;text-align:left}th{background:#dbeafe}.print-btn{position:fixed;right:20px;top:20px}@media print{.print-btn{display:none}}</style></head><body><button class="print-btn" onclick="window.print()">Cetak / Simpan PDF</button><div class="header"><img src="<?= url(SCHOOL_LOGO) ?>" class="logo"><div><h1>Laporan Akademik PABETAS</h1><p>Pretest, posttest, peningkatan nilai, dan remedial otomatis</p></div></div><div><div class="stat"><b><?= e($sum['avg_pretest']) ?></b>Rata-rata Pretest</div><div class="stat"><b><?= e($sum['avg_posttest']) ?></b>Rata-rata Posttest</div><div class="stat"><b><?= e($sum['avg_improvement']) ?></b>Rata-rata Peningkatan</div><div class="stat"><b><?= e($sum['mastery_percent']) ?>%</b>Ketuntasan</div></div><table><thead><tr><th>Nama</th><th>Pretest</th><th>Posttest</th><th>Peningkatan</th><th>Remedial</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r): $imp=($r['pretest']!==null&&$r['posttest']!==null)?((int)$r['posttest']-(int)$r['pretest']):null; ?><tr><td><?= e($r['name']) ?></td><td><?= $r['pretest']!==null?e($r['pretest']):'-' ?></td><td><?= $r['posttest']!==null?e($r['posttest']):'-' ?></td><td><?= $imp!==null?(($imp>=0?'+':'').e($imp)):'-' ?></td><td><?= ((int)$r['remedial_open']===1)?'Perlu':'Tidak' ?></td><td><?= ($r['posttest']!==null && (int)$r['posttest']>=REMEDIAL_MIN_SCORE)?'Tuntas':'Belum lengkap/tidak tuntas' ?></td></tr><?php endforeach; ?></tbody></table><p style="margin-top:24px">Dicetak pada: